const filterName = components.searchByDimensionFormSelectFilter.value;
const filterValue = components.searchByDimensionFormTextInputValue.value;
let tempFilters = page.variables.filtersOnDimensionArray; 

// Check if dimension already present

for(let i = 0; i < tempFilters.length; i++) {
  if(filterName === tempFilters[i].dimension_name) {
    const type = tempFilters[i].type;
    if(type === "TYPE_STRING") {
      tempFilters[i].string_value = filterValue;
    } else {
      tempFilters[i].integer_value = JSON.parse(filterValue);
    } 
   // filtersOnDimensionArray.setValue(tempFilters);
    await actions.setPageVariable("filtersOnDimensionArray",tempFilters)
    return;
  }
} 

// Add new dimension
let obj = {};
obj.dimension_name = filterName;
let allDimensions =  queries.fetchConfigDetails.data.Dimensions;
for(let i = 0; i < allDimensions.length; i++) {
  if(allDimensions[i].dimension_name === filterName) {
    obj.type = allDimensions[i].type;
    break;
  }
}
if(obj.type === "TYPE_STRING") {
  obj.string_value = filterValue;
} else {
  obj.integer_value = JSON.parse(filterValue);
}  
tempFilters.push(obj);
//filtersOnDimensionArray.setValue(tempFilters);
await actions.setPageVariable("filtersOnDimensionArray",tempFilters)
